import React, { useState, useRef, useEffect } from "react";
import axios from "axios";

function App() {

  const [messages,setMessages] = useState([]);
  const [input,setInput] = useState("");
  const [loading,setLoading] = useState(false);

  const bottomRef = useRef(null);

  useEffect(()=>{
    bottomRef.current?.scrollIntoView({behavior:"smooth"});
  },[messages]);

  const sendMessage = async () => {

    if(!input.trim()) return;

    const userMsg = {
      role:"user",
      text:input,
      time:new Date().toLocaleTimeString()
    };

    setMessages(prev=>[...prev,userMsg]);
    setInput("");
    setLoading(true);

    try{

      const res = await axios.post(
        "http://localhost:5002/chat",
        {message:userMsg.text}
      );

      const aiMsg = {
        role:"ai",
        text:res.data.reply,
        time:new Date().toLocaleTimeString()
      };

      setMessages(prev=>[...prev,aiMsg]);

    }catch(err){

      setMessages(prev=>[
        ...prev,
        {role:"ai",text:"Error contacting AI"}
      ]);

    }

    setLoading(false);
  };

  const handleKey = (e)=>{
    if(e.key==="Enter"){
      sendMessage();
    }
  };

  const clearChat = ()=>{
    setMessages([]);
  };

  return(

  <div style={styles.container}>

    <div style={styles.chatCard}>

      <div style={styles.header}>
        🤖 AI Assistant
        <button style={styles.clearBtn} onClick={clearChat}>
          Clear
        </button>
      </div>

      <div style={styles.chatBox}>

        {messages.map((msg,i)=>(

          <div
            key={i}
            style={msg.role==="user"?styles.userRow:styles.aiRow}
          >

            <div style={styles.avatar}>
              {msg.role==="user"?"🧑":"🤖"}
            </div>

            <div style={styles.bubble}>

              <div>{msg.text}</div>

              <div style={styles.time}>
                {msg.time}
              </div>

            </div>

          </div>

        ))}

        {loading && (

          <div style={styles.aiRow}>
            <div style={styles.avatar}>🤖</div>
            <div style={styles.bubble}>
              AI is thinking...
            </div>
          </div>

        )}

        <div ref={bottomRef}></div>

      </div>

      <div style={styles.inputArea}>

        <input
          style={styles.input}
          value={input}
          onChange={(e)=>setInput(e.target.value)}
          onKeyDown={handleKey}
          placeholder="Ask something..."
        />

        <button
          style={styles.send}
          onClick={sendMessage}
        >
          Send
        </button>

      </div>

    </div>

  </div>

  );

}

const styles={

container:{
height:"100vh",
background:"#0f172a",
display:"flex",
justifyContent:"center",
alignItems:"center",
fontFamily:"Arial"
},

chatCard:{
width:"650px",
height:"700px",
background:"#1e293b",
borderRadius:"12px",
display:"flex",
flexDirection:"column",
overflow:"hidden",
boxShadow:"0 10px 30px rgba(0,0,0,0.4)"
},

header:{
padding:"15px",
color:"white",
fontSize:"18px",
borderBottom:"1px solid #334155",
display:"flex",
justifyContent:"space-between"
},

clearBtn:{
background:"#ef4444",
border:"none",
color:"white",
padding:"5px 10px",
borderRadius:"6px",
cursor:"pointer"
},

chatBox:{
flex:1,
overflowY:"auto",
padding:"20px",
display:"flex",
flexDirection:"column",
gap:"15px"
},

userRow:{
display:"flex",
justifyContent:"flex-end",
gap:"10px"
},

aiRow:{
display:"flex",
justifyContent:"flex-start",
gap:"10px"
},

avatar:{
fontSize:"22px"
},

bubble:{
background:"#334155",
color:"white",
padding:"10px 15px",
borderRadius:"10px",
maxWidth:"70%"
},

time:{
fontSize:"10px",
opacity:0.6,
marginTop:"4px"
},

inputArea:{
display:"flex",
padding:"15px",
borderTop:"1px solid #334155"
},

input:{
flex:1,
padding:"10px",
borderRadius:"8px",
border:"none",
outline:"none"
},

send:{
marginLeft:"10px",
padding:"10px 15px",
border:"none",
borderRadius:"8px",
background:"#3b82f6",
color:"white",
cursor:"pointer"
}

};

export default App;
